Hi, 

I have been working on integrating my angularjs mobile website with django backend. 

I am able to send the token properly to python social auth and I am able to authenticate the user and I am getting the user model from the code

But I am not able to perform a _do_login, I have found that this is because of some code improvements in the plugin and I do not know the new implementations of the newer version. Please help me out with this. I am using 0.2.2 of psa and django 1.7.4

Here is the code for my views.py. 

```
@psa()
def auth_by_token(request, backend):
    backend = request.backend
    user=request.user
    user = backend.do_auth(
        access_token=request.DATA.get('access_token'),
        user=user.is_authenticated() and user or None
        )
    if user and user.is_active:
        return user # Return anything that makes sense here
    else:
        return None



@csrf_exempt
@api_view(['POST'])
@permission_classes((AllowAny,))
def social_register(request):
    auth_token = request.DATA.get('access_token', None)
    backend = request.DATA.get('backend', None)
    if auth_token and backend:
        try:
            user = auth_by_token(request, backend)
        except Exception, err:
            return Response(str(err), status=400)
        if user:
            # TO FIX STRATEGY LOGIC.
            strategy = load_strategy(request=request, backend=backend)
            _do_login(strategy, user)
            return Response( "User logged in", status=status.HTTP_200_OK )
        else:
            return Response("Bad Credentials", status=403)
    else:
        return Response("Bad request", status=400)

```

